import secrets
import string
from pyotp import TOTP, random_base32
from qrcode.image.svg import SvgImage
from qrcode import QRCode
import hashlib
import hmac
import time
import logging

# Set up secure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

def generate_totp_secret(length=16):
    """Generate a TOTP secret."""
    alphabet = string.ascii_letters + string.digits
    return ''.join(secrets.choice(alphabet) for _ in range(length))

def generate_qr_code(secret, user_name):
    """Create a QR code for the authenticator app."""
    totp = TOTP(secret)
    qr = QRCode(
        version=1,
        error_correction=0,
        box_size=10,
        border=4
    )
    qr.add_data(totp.provisioning_uri(user_name, issuer_name="My MFA System"))
    return qr.make_image(fill_color="black", back_color="white")

def validate_totp_code(secret, user_input):
    """Validate the TOTP code."""
    totp = TOTP(secret)
    expected_code = totp.now()
    try:
        if hmac.compare_digest(str(user_input), str(expected_code)):
            return True
    except ValueError:
        logger.error("Invalid input")
    return False

